### 6. gRPC Proto 정의

파일 위치: `protobuf/src/main/proto/profile/profile.proto`

```protobuf
syntax = "proto3";
package profile;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.profile";

service ProfileService {
  rpc GetProfile(GetProfileRequest) returns (GetProfileResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
}

// ── Enum ──────────────────────────────────
enum Gender {
  GENDER_UNKNOWN = 0;
  GENDER_MALE = 1;
  GENDER_FEMALE = 2;
  GENDER_OTHER = 3;
}

// ── Messages ──────────────────────────────
message Profile {
  string id = 1;
  string user_id = 2;
  string nickname = 3;
  optional string bio = 4;
  optional string profile_image_url = 5;
  optional string voice_intro_url = 6;
  optional int32 birth_year = 7;
  Gender gender = 8;
  optional string job = 9;
  optional string region = 10;
  repeated string interests = 11;
  string created_at = 12;
  string updated_at = 13;
}

message GetProfileRequest {
  string user_id = 1;
}

message GetProfileResponse {
  Profile profile = 1;
}

message UpdateProfileRequest {
  string user_id = 1;
  optional string nickname = 2;
  optional string bio = 3;
  optional string profile_image_url = 4;
  optional string voice_intro_url = 5;
  optional int32 birth_year = 6;
  optional Gender gender = 7;
  optional string job = 8;
  optional string region = 9;
  repeated string interests = 10;
}

message UpdateProfileResponse {
  Profile profile = 1;
}
```

