### 7. Entity 참고 정의

파일 위치: `domain/src/main/kotlin/com/maum/backend/entity/profile/ProfileEntity.kt`

```kotlin
@Entity
@Table(catalog = "maum", name = "profile")
class ProfileEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val userId: String,

    var nickname: String,
    var bio: String? = null,
    var profileImageUrl: String? = null,
    var voiceIntroUrl: String? = null,
    var birthYear: Int? = null,
    var gender: Int = 0,           // Gender enum의 value로 저장
    var job: String? = null,
    var region: String? = null,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
```

